{
 "level": "A2–B2",
 "intro": "In this guide, you will learn five common ways of talking about the future: <strong>will</strong>, <strong>be going to</strong>, <strong>Future Continuous</strong>, <strong>Future Perfect</strong>, and <strong>Future Perfect Continuous</strong>.",
 "rules": [
 {
 "label": "WILL",
 "color": "blue",
 "text": "Spontaneous decisions, promises, requests, and neutral predictions:",
 "example": "I'll help you. / I think it will rain."
 },
 {
 "label": "BE GOING TO",
 "color": "emerald",
 "text": "Plans, intentions, and predictions based on visible evidence:",
 "example": "We're going to move. / It's going to rain."
 },
 {
 "label": "FUTURE CONTINUOUS",
 "color": "amber",
 "text": "Actions that will be in progress at a future moment, or softer questions about arrangements:",
 "example": "This time tomorrow, I'll be flying. / Will you be using the car tonight?"
 },
 {
 "label": "FUTURE PERFECT",
 "color": "violet",
 "text": "Actions that will already be complete by a future moment or deadline:",
 "example": "By Friday, I'll have finished the report."
 },
 {
 "label": "FUTURE PERFECT CONTINUOUS",
 "color": "rose",
 "text": "Processes or durations that will still be continuing up to a future moment or event:",
 "example": "By next month, I'll have been working here for five years."
 }
 ]
}

{
 "title": "What you will study here",
 "intro": "Future forms cover several common meanings. Focus on why the speaker chooses the form, not only on the future time.",
 "rows": [
 {
 "en": "Will",
 "ua": "Will",
 "note": "spontaneous decisions, promises, opinions, and predictions: I'll answer it. / I think she will arrive."
 },
 {
 "en": "Be going to",
 "ua": "Be going to",
 "note": "intentions or plans that already exist: We're going to move house."
 },
 {
 "en": "Be going to",
 "ua": "Be going to",
 "note": "predictions based on present evidence: Look at the clouds. It's going to rain."
 },
 {
 "en": "Future Continuous",
 "ua": "Future Continuous",
 "note": "actions in progress at a future moment: At 8 p.m. tomorrow, we'll be having dinner."
 },
 {
 "en": "Future Perfect",
 "ua": "Future Perfect",
 "note": "actions already complete by a future point or deadline: By next week, we'll have finished."
 },
 {
 "en": "Future Perfect Continuous",
 "ua": "Future Perfect Continuous",
 "note": "processes or durations up to a future point or event: By next month, I'll have been working here for five years."
 },
 {
 "en": "Choice of form",
 "ua": "Choice of form",
 "note": "The same future event can sound different when the focus is decision, plan, evidence, process, completed result, or duration before a future point."
 }
 ],
 "warning": "With future forms, ask: is this a decision now, an existing plan, visible evidence, an action in progress, a completed result, or a duration that leads up to a future deadline?"
}
